mapper.sql:
SELECT A.SEQ ,TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM ,A.CONTRACT_NUM ,B.SUB_STATUS ,FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM ,B.BAN ,B.SUB_LINK_NAME AS CSTMR_NAME ,A.DOC_TYPE ,FN_GET_CODENM('ACEN0001', A.DOC_TYPE) AS DOC_TYPE_NAME ,A.RECEIVE_TYPE ,FN_GET_CODENM('ACEN0002', A.RECEIVE_TYPE) AS RECEIVE_TYPE_NAME ,A.FAX_NO ,DECODE(A.START_YM, NULL, '', SUBSTR(A.START_YM, 1, 4) || '-' || SUBSTR(A.START_YM, 5)) AS START_YM ,DECODE(A.END_YM, NULL, '', SUBSTR(A.END_YM, 1, 4) || '-' || SUBSTR(A.END_YM, 5)) AS END_YM ,A.STATUS ,FN_GET_CODENM('ACEN0003', A.STATUS) AS STATUS_NAME ,TO_CHAR(A.PROC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM ,FN_GET_USRNM(A.PROC_ID) AS PROC_NAME ,TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM ,FN_GET_USRNM(A.RVISN_ID) AS RVISN_NAME FROM NMCP_ACEN_DOC_REQ@DL_MCP A ,MSP_JUO_SUB_INFO B ,MSP_REQUEST_DTL C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND A.REGST_DTTM BETWEEN TO_DATE(#{srchStrtDt},'YYYYMMDD') AND TO_DATE(#{srchEndDt},'YYYYMMDD') + 1
AND A.STATUS = '01' AND A.PROC_DTTM BETWEEN TO_DATE(#{compStrtDt},'YYYYMMDD') AND TO_DATE(#{compEndDt},'YYYYMMDD') + 1
AND (B.OPEN_AGNT_CD = #{cntpntShopId} OR TRIM(SUBSTR(C.DVC_CHG_INFO, 69, 10)) = #{cntpntShopId})
AND A.DOC_TYPE = #{docType}
AND A.RECEIVE_TYPE = #{receiveType}
AND A.STATUS = #{status}
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND C.LST_RATE_NM LIKE '%' || #{searchName} || '%'
AND UPPER(B.SUB_LINK_NAME) LIKE UPPER(#{searchName}) || '%'
AND B.BAN = #{searchName}
AND A.FAX_NO = #{searchName}
ORDER BY A.SEQ DESC

mapper.update:
/*AcenReceptionMapper.completeAcenReception*/
UPDATE NMCP_ACEN_DOC_REQ@DL_MCP
SET STATUS = #{status}
	 ,RVISN_ID = #{sessionUserId}
	 ,RVISN_DTTM = SYSDATE
	 ,PROC_ID = #{sessionUserId}
	 ,PROC_DTTM = SYSDATE
WHERE SEQ = #{seq}

/*AcenReceptionMapper.cancelAcenReception*/
UPDATE NMCP_ACEN_DOC_REQ@DL_MCP
SET STATUS = #{status}
	 ,RVISN_ID = #{sessionUserId}
	 ,RVISN_DTTM = SYSDATE
	 ,PROC_ID = NULL
	 ,PROC_DTTM = NULL
WHERE SEQ = #{seq}

mapper.insert:
/*AcenReceptionMapper.insertAcenReceptionHist*/
INSERT INTO NMCP_ACEN_DOC_HIST@DL_MCP(
	 SEQ
	,SUB_SEQ
	,STATUS
	,REGST_ID
	,REGST_DTTM
)VALUES(
	 #{seq}
  	,NVL((SELECT MAX(SUB_SEQ) + 1 FROM NMCP_ACEN_DOC_HIST@DL_MCP WHERE SEQ = #{seq}), 1)
	,#{status}
	,#{sessionUserId}
	,SYSDATE
)
